// Fetch published posts from last 7 days to analyze performance
const SUPABASE_URL = $env.SUPABASE_URL || 'https://xhpfxvoonpclonjyfimt.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const headers = { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json' };

const since7d = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();

// Get published posts
let posts;
try {
  posts = await this.helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/posts?select=id,title,slug,category,created_at,seo_score,primary_keyword&status=eq.published&created_at=gte.' + since7d + '&order=created_at.desc',
    headers: headers, json: true
  });
} catch (e) { posts = []; }
if (!Array.isArray(posts)) posts = [];

// Get existing performance snapshots for today
const today = new Date().toISOString().split('T')[0];
let existingSnapshots;
try {
  existingSnapshots = await this.helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/post_performance?select=post_id&snapshot_date=eq.' + today,
    headers: headers, json: true
  });
} catch (e) { existingSnapshots = []; }
if (!Array.isArray(existingSnapshots)) existingSnapshots = [];
const alreadySnapped = new Set(existingSnapshots.map(s => s.post_id));

// Get distribution data
let distributions;
try {
  const postIds = posts.map(p => p.id);
  if (postIds.length > 0) {
    distributions = await this.helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/post_distributions?select=post_id,channel,status,engagement&post_id=in.(' + postIds.join(',') + ')',
      headers: headers, json: true
    });
  } else { distributions = []; }
} catch (e) { distributions = []; }
if (!Array.isArray(distributions)) distributions = [];

// Get sitemap indexing status
let sitemapEntries;
try {
  const slugs = posts.map(p => p.slug).filter(Boolean);
  if (slugs.length > 0) {
    sitemapEntries = await this.helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/sitemap_entries?select=post_id,indexed,indexed_at,submitted_to_gsc',
      headers: headers, json: true
    });
  } else { sitemapEntries = []; }
} catch (e) { sitemapEntries = []; }
if (!Array.isArray(sitemapEntries)) sitemapEntries = [];
const sitemapByPost = {};
for (const se of sitemapEntries) { if (se.post_id) sitemapByPost[se.post_id] = se; }

// Get curated post data (for editorial_score, tone_profile)
let curatedLookup = {};
try {
  const curatedResp = await this.helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/curated_posts?select=id,editorial_score,tone_profile,model_info,primary_keyword,topic&created_at=gte.' + since7d,
    headers: headers, json: true
  });
  if (Array.isArray(curatedResp)) {
    for (const cp of curatedResp) { curatedLookup[cp.id] = cp; }
  }
} catch (e) { /* ok */ }

// Build distribution map
const distByPost = {};
for (const d of distributions) {
  if (!distByPost[d.post_id]) distByPost[d.post_id] = [];
  distByPost[d.post_id].push(d);
}

const output = [];
for (const post of posts) {
  if (alreadySnapped.has(post.id)) continue;

  const dists = distByPost[post.id] || [];
  const socialShares = dists.filter(d => d.status === 'sent').length;
  const socialClicks = dists.reduce((sum, d) => sum + ((d.engagement || {}).clicks || 0), 0);
  const sitemap = sitemapByPost[post.id] || {};
  const indexedAt = sitemap.indexed_at ? new Date(sitemap.indexed_at) : null;
  const createdAt = new Date(post.created_at);
  const timeToIndex = indexedAt ? ((indexedAt - createdAt) / (1000 * 60 * 60)) : null;

  // Calculate performance score composite
  let perfScore = 0;
  perfScore += sitemap.indexed ? 20 : 0;  // indexed = base 20
  perfScore += socialShares > 0 ? 15 : 0;  // has social distribution
  perfScore += (post.seo_score || 0) > 50 ? 15 : 0;  // good SEO
  perfScore += timeToIndex !== null && timeToIndex < 48 ? 20 : 0;  // fast indexing
  perfScore += socialClicks > 0 ? 15 : 0;  // has engagement
  perfScore += dists.filter(d => d.status === 'failed').length === 0 ? 15 : 0;  // no failures
  perfScore = Math.min(perfScore, 100);

  output.push({
    json: {
      post_id: post.id,
      topic: post.category || null,
      primary_keyword: post.primary_keyword || null,
      editorial_score: null,  // will be filled from curated
      tone_profile: null,
      model_info: {},
      google_indexed: sitemap.indexed || false,
      indexed_at: sitemap.indexed_at || null,
      time_to_index_hours: timeToIndex,
      social_shares: socialShares,
      social_clicks: socialClicks,
      performance_score: perfScore,
      snapshot_date: today
    }
  });
}

if (output.length === 0) {
  return [{ json: { skip: true, message: 'No new performance data to snapshot' } }];
}

return output;

// Weekly learning report — analyze patterns in performance data
const SUPABASE_URL = $env.SUPABASE_URL || 'https://xhpfxvoonpclonjyfimt.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const headers = { 'apikey': SUPABASE_KEY, 'Content-Type': 'application/json' };

// Only run full report on Sundays (or if forced)
const dow = new Date().getDay();
if (dow !== 0) {
  return [{ json: { report_skipped: true, reason: 'Not Sunday (day=' + dow + ')' } }];
}

const since30d = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString();
let allPerf;
try {
  allPerf = await this.helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/post_performance?select=*&created_at=gte.' + since30d + '&order=performance_score.desc',
    headers: headers, json: true
  });
} catch (e) { allPerf = []; }
if (!Array.isArray(allPerf)) allPerf = [];

// Analyze by topic
const byTopic = {};
for (const p of allPerf) {
  const topic = p.topic || 'geral';
  if (!byTopic[topic]) byTopic[topic] = { total: 0, totalScore: 0, indexed: 0, totalIndexTime: 0, indexedCount: 0 };
  byTopic[topic].total++;
  byTopic[topic].totalScore += (p.performance_score || 0);
  if (p.google_indexed) byTopic[topic].indexed++;
  if (p.time_to_index_hours) { byTopic[topic].totalIndexTime += p.time_to_index_hours; byTopic[topic].indexedCount++; }
}

const topicInsights = Object.entries(byTopic).map(([topic, data]) => ({
  topic: topic,
  avg_performance: Math.round(data.totalScore / data.total),
  index_rate: Math.round(data.indexed / data.total * 100),
  avg_index_hours: data.indexedCount > 0 ? Math.round(data.totalIndexTime / data.indexedCount) : null,
  post_count: data.total
})).sort((a, b) => b.avg_performance - a.avg_performance);

// Top performing keywords
const byKeyword = {};
for (const p of allPerf) {
  if (!p.primary_keyword) continue;
  if (!byKeyword[p.primary_keyword]) byKeyword[p.primary_keyword] = { total: 0, totalScore: 0 };
  byKeyword[p.primary_keyword].total++;
  byKeyword[p.primary_keyword].totalScore += (p.performance_score || 0);
}
const topKeywords = Object.entries(byKeyword).map(([kw, data]) => ({
  keyword: kw, avg_score: Math.round(data.totalScore / data.total), count: data.total
})).sort((a, b) => b.avg_score - a.avg_score).slice(0, 10);

// Summary
const totalPosts = allPerf.length;
const avgScore = totalPosts > 0 ? Math.round(allPerf.reduce((s, p) => s + (p.performance_score || 0), 0) / totalPosts) : 0;
const indexedCount = allPerf.filter(p => p.google_indexed).length;
const indexRate = totalPosts > 0 ? Math.round(indexedCount / totalPosts * 100) : 0;

const report = {
  period: '30 days',
  generated_at: new Date().toISOString(),
  total_posts_analyzed: totalPosts,
  avg_performance_score: avgScore,
  overall_index_rate: indexRate + '%',
  best_topics: topicInsights.slice(0, 3),
  worst_topics: topicInsights.slice(-2),
  top_keywords: topKeywords,
  recommendations: []
};

// Generate actionable recommendations
if (indexRate < 50) report.recommendations.push('Taxa de indexacao baixa (' + indexRate + '%). Aumentar pings ao Google e verificar sitemap.');
if (avgScore < 40) report.recommendations.push('Performance media baixa. Focar em keywords com melhor historico: ' + (topKeywords[0]?.keyword || 'N/A'));
if (topicInsights.length > 0 && topicInsights[0].avg_performance > 60) report.recommendations.push('Topico "' + topicInsights[0].topic + '" tem melhor performance. Considerar mais conteudo nesta area.');
if (topicInsights.length > 1 && topicInsights[topicInsights.length - 1].avg_performance < 30) report.recommendations.push('Topico "' + topicInsights[topicInsights.length - 1].topic + '" com performance fraca. Revisar estrategia ou reduzir volume.');

// Save learning report as alert
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: SUPABASE_URL + '/rest/v1/pipeline_alerts',
    headers: headers,
    body: {
      alert_type: 'weekly_learning_report',
      severity: 'info',
      title: 'Relatorio Semanal de Performance',
      detail: 'Posts: ' + totalPosts + ' | Score medio: ' + avgScore + ' | Indexacao: ' + indexRate + '%',
      metadata: report,
      resolved: true,
      resolved_at: new Date().toISOString()
    },
    json: true
  });
} catch (e) { /* ok */ }

// Send report email
try {
  const emailHtml = '<h2>Relatorio Semanal Vision7</h2>' +
    '<p><strong>Periodo:</strong> Ultimos 30 dias</p>' +
    '<p><strong>Posts analisados:</strong> ' + totalPosts + '</p>' +
    '<p><strong>Score medio:</strong> ' + avgScore + '/100</p>' +
    '<p><strong>Taxa de indexacao:</strong> ' + indexRate + '%</p>' +
    '<h3>Melhores Topicos</h3><ul>' + topicInsights.slice(0, 3).map(t => '<li>' + t.topic + ': ' + t.avg_performance + ' pts (' + t.post_count + ' posts)</li>').join('') + '</ul>' +
    '<h3>Top Keywords</h3><ul>' + topKeywords.slice(0, 5).map(k => '<li>' + k.keyword + ': ' + k.avg_score + ' pts</li>').join('') + '</ul>' +
    '<h3>Recomendacoes</h3><ul>' + report.recommendations.map(r => '<li>' + r + '</li>').join('') + '</ul>';

  await this.helpers.httpRequest({
    method: 'POST',
    url: SUPABASE_URL + '/functions/v1/send-email',
    headers: { ...headers, 'Authorization': 'Bearer ' + SUPABASE_KEY },
    body: {
      to: $env.ADMIN_EMAIL || 'admin@vision7.pt',
      subject: '[Vision7] Relatorio Semanal — Score ' + avgScore + ' | Indexacao ' + indexRate + '%',
      html: emailHtml
    },
    json: true
  });
} catch (e) { /* email send failed */ }

return [{ json: report }];
